package form;
import controller.KelasController;import model.Kelas;import util.UIUtils;import javax.swing.*;import javax.swing.table.DefaultTableModel;import java.awt.*;
public class KelasForm extends JPanel{DefaultTableModel m=new DefaultTableModel(new String[]{"ID","Kode","Nama Kelas"},0);KelasController c=new KelasController();public KelasForm(){setLayout(new BorderLayout());JPanel p=UIUtils.page("CRUD Kelas");JTextField kode=UIUtils.textField(8),nama=UIUtils.textField(18);JButton sim=UIUtils.button("Simpan",UIUtils.BLUE);sim.addActionListener(e->{try{c.simpan(new Kelas(0,kode.getText(),nama.getText()));load();}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});p.add(UIUtils.toolbar(UIUtils.formLabel("Kode"),kode,UIUtils.formLabel("Nama"),nama,sim),BorderLayout.CENTER);p.add(UIUtils.tableScroll(new JTable(m)),BorderLayout.SOUTH);add(p);load();}void load(){m.setRowCount(0);try{for(Kelas k:c.getAll())m.addRow(new Object[]{k.getIdKelas(),k.getKodeKelas(),k.getNamaKelas()});}catch(Exception ignored){}}}
